const ragResult = $input.first().json;
const trigger = $('Вызов из другого workflow').item.json;
const topic = trigger.rag_topic || trigger.topic || '';
const ragContext = ragResult.context || '';
let messages = [...(trigger.messages || [])];

if (ragContext) {
  // Ищем последний system message и добавляем в него контекст НПА
  const sysIdx = messages.findLastIndex(m => m.role === 'system');
  if (sysIdx >= 0) {
    messages[sysIdx] = {
      ...messages[sysIdx],
      content: messages[sysIdx].content + '\n\n---\n' + ragContext
    };
  } else {
    // Если system message нет — добавляем в начало
    messages.unshift({ role: 'system', content: ragContext });
  }
}

return [{ json: { messages, topic, sessionId: trigger.sessionId } }];

const response = $input.first().json;
const responseText = response?.message?.content || '';
return [{ json: { response: responseText } }];
